compliant:
[Serializable]
public class BankAccount : IDeserializationCallback
{
    public decimal Balance { get; set; }
    public string AccountNumber { get; set; }

    public BankAccount(decimal balance, string accountNumber)
    {
        ValidateBalance(balance);
        Balance = balance;
        AccountNumber = accountNumber;
    }

    public void OnDeserialization(object sender)
    {
        ValidateBalance(Balance); // Compliant: Validation applied
    }

    private void ValidateBalance(decimal balance)
    {
        if (balance < 0)
            throw new ArgumentException("Balance cannot be negative");
    }
}

[Serializable]
public class User : IDeserializationCallback
{
    public string Email { get; set; }
    public int Age { get; set; }

    public User(string email, int age)
    {
        Validate(age);
        Email = email;
        Age = age;
    }

    public void OnDeserialization(object sender)
    {
        Validate(Age); // Compliant: Validation during deserialization
    }

    private void Validate(int age)
    {
        if (age < 0 || age > 150)
            throw new ArgumentException("Invalid age");
    }
}

[Serializable]
public class Configuration
{
    private string databaseConnection;

    public string DatabaseConnection
    {
        get => databaseConnection;
        set
        {
            ValidateConnection(value);
            databaseConnection = value;
        }
    }

    private void ValidateConnection(string connection)
    {
        if (string.IsNullOrEmpty(connection))
            throw new ArgumentException("Connection string required");
    }
    // Compliant: Validation in property setter applies during deserialization
}

